module top_module(
   input         clock, write, reset,
   input [15:0]  writeData,
   output [15:0] data);reg [15:0]    obf_out = 16'b0;

   always @ (posedge clock) begin 
      if (reset)
         obf_out = 16'b0;
      else if (write)
         obf_out = writeData;
   end

   assign data = obf_out;
endmodule
